mapper.select:
SELECT m.id, m.major_name, m.major_code, m.department_id, d.dept_name as department_name, m.description, m.status, CASE m.status WHEN 1 THEN '启用' WHEN 0 THEN '禁用' ELSE '未知' END as status_name, m.created_at, m.updated_at FROM majors m LEFT JOIN departments d ON m.department_id = d.id WHERE m.deleted = 0
AND m.major_name LIKE CONCAT('%', #{params.majorName}, '%')
AND m.major_code LIKE CONCAT('%', #{params.majorCode}, '%')
AND m.department_id = #{params.departmentId}
AND m.status = #{params.status}
ORDER BY m.created_at DESC
